sql:
SELECT COUNT(*) 
FROM batteries 
WHERE battery_type = 'Lead-acid';

SELECT metric_id
FROM battery_metrics
WHERE health_index < 90;

SELECT setting_name, value 
FROM system_settings
WHERE last_updated >= datetime('now', '-30 days');

SELECT * 
FROM batteries 
WHERE location = (
  SELECT location 
  FROM batteries 
  WHERE capacity = (
    SELECT MAX(capacity) 
    FROM batteries
  )
);

SELECT u.username, a.alert_type
FROM users u
JOIN alerts a ON u.user_id = a.resolved_by;

SELECT model_name
FROM battery_models
WHERE release_date > '2023-01-01';

SELECT battery_id, battery_type, capacity 
FROM batteries 
WHERE capacity > (SELECT AVG(capacity) FROM batteries);

